INSERT INTO quiz_questions (quiz_id, question_text, question_type, options, correct_answer, explanation)
VALUES
('6e54a9fe-a98e-4b88-bf6c-cd2a6e7d13cc', 'Bối cảnh nào yêu cầu bạn phải viết một bức Thư trang trọng (Formal Letter)?', 'multiple_choice', '["Viết cho người yêu cũ.","Viết cho hàng xóm mượn dụng cụ.","Viết cho một công ty, tổ chức, hoặc một người có thẩm quyền mà bạn KHÔNG BIẾT TÊN (ví dụ: Quản lý nhà hàng, Hội đồng thành phố) để phàn nàn hoặc yêu cầu thông tin.","Viết thiệp chúc mừng sinh nhật."]', 'Viết cho một công ty, tổ chức, hoặc một người có thẩm quyền mà bạn KHÔNG BIẾT TÊN (ví dụ: Quản lý nhà hàng, Hội đồng thành phố) để phàn nàn hoặc yêu cầu thông tin.', 'Formal Letter áp dụng cho các tương tác hành chính, kinh doanh với người lạ hoàn toàn.'),
('6e54a9fe-a98e-4b88-bf6c-cd2a6e7d13cc', 'Cặp Lời chào (Greeting) và Lời kết (Sign-off) nào là BẮT BUỘC ĐI KÈM với nhau trong Formal Letter khi bạn không biết tên người nhận?', 'multiple_choice', '["Dear Mr. John, / Yours faithfully,","Dear Sir or Madam, / Yours faithfully,","Dear Sir or Madam, / Yours sincerely,","Hi there, / See you soon,"]', 'Dear Sir or Madam, / Yours faithfully,', 'Đây là quy tắc vàng của tiếng Anh Anh: Không biết tên (Sir/Madam) thì kết bằng ''Yours faithfully''. Biết tên (Mr. Brown) thì kết bằng ''Yours sincerely''.'),
('6e54a9fe-a98e-4b88-bf6c-cd2a6e7d13cc', 'Khi bắt đầu một lá thư phàn nàn (Letter of complaint) trang trọng, cấu trúc nào là chuyên nghiệp nhất?', 'multiple_choice', '["I hate your company because...","I am writing to express my extreme dissatisfaction with...","Your service is totally rubbish.","I want to complain right now about..."]', 'I am writing to express my extreme dissatisfaction with...', 'Dù tức giận đến đâu, ngôn ngữ trong Formal Letter vẫn phải giữ sự điềm tĩnh và học thuật. ''Express dissatisfaction'' là cụm từ đắt giá cho dạng bài này.'),
('64a0942d-ec53-486f-93e4-c1e926ab7c24', 'Trong tiêu chí chấm điểm ''Task Achievement'' của Writing Task 1 Academic, lỗi nào sẽ khiến bạn không bao giờ vượt qua Band 5.0?', 'multiple_choice', '["Thiếu mất một vài dấu phẩy.","Quên không viết phần Overview (Tổng quan) hoặc viết Overview nhưng không tóm tắt được xu hướng/đặc điểm chính.","Sử dụng sai thì quá khứ.","Chữ viết tay hơi xấu."]', 'Quên không viết phần Overview (Tổng quan) hoặc viết Overview nhưng không tóm tắt được xu hướng/đặc điểm chính.', 'Luật của IELTS quy định rất rõ: ''No overview, no more than Band 5 for Task Achievement''. Overview là trái tim của bài báo cáo số liệu.'),
('64a0942d-ec53-486f-93e4-c1e926ab7c24', 'Trong Task 1, việc bạn đưa ''Ý kiến cá nhân'' (Ví dụ: ''Tỷ lệ tội phạm tăng có lẽ là do thất nghiệp'') vào bài phân tích biểu đồ sẽ dẫn đến hậu quả gì?', 'multiple_choice', '["Được cộng thêm điểm vì hiểu biết sâu sắc xã hội.","Bị trừ điểm Task Achievement vì bài thi chỉ yêu cầu mô tả khách quan dữ liệu có trên hình, nghiêm cấm suy diễn nguyên nhân/kết quả cá nhân.","Không ảnh hưởng gì.","Được giám khảo khen ngợi."]', 'Bị trừ điểm Task Achievement vì bài thi chỉ yêu cầu mô tả khách quan dữ liệu có trên hình, nghiêm cấm suy diễn nguyên nhân/kết quả cá nhân.', 'Task 1 kiểm tra khả năng ''Report'' (Báo cáo) số liệu. Chức năng đưa quan điểm cá nhân (Opinion) chỉ dành riêng cho Task 2.'),
('64a0942d-ec53-486f-93e4-c1e926ab7c24', 'Việc sử dụng các cụm từ (Chunks) thuộc lòng học vẹt (ví dụ: ''It is patently obvious from the graph that...'') ảnh hưởng thế nào đến điểm Lexical Resource?', 'multiple_choice', '["Giúp đạt Band 8.0 trở lên dễ dàng.","Giám khảo sẽ bỏ qua, không tính các từ đó vào tổng số từ của bài và có thể trừ điểm vì tính thiếu tự nhiên (Cliché/Memorized language).","Giúp bài viết dài hơn và chắc chắn điểm cao.","Giám khảo rất thích các cụm từ này."]', 'Giám khảo sẽ bỏ qua, không tính các từ đó vào tổng số từ của bài và có thể trừ điểm vì tính thiếu tự nhiên (Cliché/Memorized language).', 'IELTS trừng phạt rất nặng việc học thuộc lòng các ''template'' sáo rỗng. Bạn phải chứng minh năng lực tự xây dựng câu từ dữ liệu thực tế.'),
('ed1b7ceb-d58e-40c2-9e28-5c6fb5b31fb6', 'Bước ĐẦU TIÊN và quan trọng nhất khi nhận được đề tài IELTS Writing Task 2 là gì?', 'multiple_choice', '["Cầm bút viết ngay lập tức để tiết kiệm thời gian.","Dành 3-5 phút để phân tích đề: gạch chân từ khóa chủ đề (Topic words), xác định rõ yêu cầu câu hỏi (Task words), và lập dàn ý (Outline).","Đếm số dòng nháp.","Viết phần Kết bài trước."]', 'Dành 3-5 phút để phân tích đề: gạch chân từ khóa chủ đề (Topic words), xác định rõ yêu cầu câu hỏi (Task words), và lập dàn ý (Outline).', 'Phân tích sai đề (Off-topic) sẽ khiến bạn bị giam điểm Task Response ở Band 5.0 dù ngữ pháp và từ vựng của bạn xuất sắc đến đâu. Planning là bước không thể bỏ qua.'),
('ed1b7ceb-d58e-40c2-9e28-5c6fb5b31fb6', 'Trong đề bài Task 2, ''Task words'' (Từ khóa yêu cầu) có chức năng gì?', 'multiple_choice', '["Cung cấp chủ đề (ví dụ: Giáo dục, Môi trường).","Chỉ định chính xác dạng bài và cấu trúc bạn phải viết (Ví dụ: ''To what extent do you agree?'', ''Discuss both views'').","Là những từ vựng khó bạn phải đưa vào bài.","Đánh lừa thí sinh."]', 'Chỉ định chính xác dạng bài và cấu trúc bạn phải viết (Ví dụ: ''To what extent do you agree?'', ''Discuss both views'').', 'Nếu đề yêu cầu ''Discuss both views and give your opinion'' mà bạn chỉ bảo vệ khăng khăng 1 bên, bạn đã thất bại hoàn toàn trong việc phản hồi yêu cầu (Task Response).'),
('ed1b7ceb-d58e-40c2-9e28-5c6fb5b31fb6', 'Khi đề bài có chứa một từ mang tính tuyệt đối (Ví dụ: ''The BEST way to reduce traffic is...''), bạn nên tiếp cận nó như thế nào khi lên dàn ý?', 'multiple_choice', '["Đồng ý tuyệt đối mà không suy nghĩ.","Thừa nhận đây là một cách tốt, nhưng phản biện rằng nó KHÔNG PHẢI LÀ DUY NHẤT hay TỐT NHẤT bằng cách đề xuất thêm các cách khác (Balanced approach).","Bỏ qua từ ''BEST'' và viết bình thường.","Chỉ trích người ra đề."]', 'Thừa nhận đây là một cách tốt, nhưng phản biện rằng nó KHÔNG PHẢI LÀ DUY NHẤT hay TỐT NHẤT bằng cách đề xuất thêm các cách khác (Balanced approach).', 'Phản biện lại tính ''tuyệt đối hóa'' (extremes) là một kỹ năng tư duy bậc cao (Band 7+) giúp bài viết có chiều sâu và sắc bén hơn.'),
('415ffae0-fc33-4076-a79e-a0bbb4a05e8a', 'Đối với dạng bài ''Opinion Essay'' (Do you agree or disagree?), yêu cầu bắt buộc đối với câu Thesis Statement ở phần Mở bài là gì?', 'multiple_choice', '["Phải đưa ra quan điểm cá nhân (Opinion) một cách RÕ RÀNG, DỨT KHOÁT ngay từ đầu và duy trì nó xuyên suốt toàn bài.","Phải giấu kín quan điểm cá nhân cho đến tận câu cuối cùng của bài.","Phải liệt kê toàn bộ các ý phụ sẽ viết trong thân bài.","Phải đặt một câu hỏi mở."]', 'Phải đưa ra quan điểm cá nhân (Opinion) một cách RÕ RÀNG, DỨT KHOÁT ngay từ đầu và duy trì nó xuyên suốt toàn bài.', 'Tiêu chí Band 7+ Task Response yêu cầu ''presents a clear position throughout the response''. Người đọc phải biết bạn ủng hộ hay phản đối ngay sau khi đọc xong Mở bài.'),
('415ffae0-fc33-4076-a79e-a0bbb4a05e8a', 'Nếu bạn chọn ''Strongly Agree'' (Đồng ý hoàn toàn) trong Opinion Essay, cấu trúc Thân bài của bạn sẽ như thế nào?', 'multiple_choice', '["Body 1 viết về Agree, Body 2 viết về Disagree.","Cả Body 1 và Body 2 đều đưa ra các luận điểm và bằng chứng để bảo vệ cho việc tại sao bạn lại Agree.","Chỉ viết 1 đoạn Body thật dài.","Không cần viết Thân bài."]', 'Cả Body 1 và Body 2 đều đưa ra các luận điểm và bằng chứng để bảo vệ cho việc tại sao bạn lại Agree.', 'Đã chọn Strong approach (Một chiều) thì toàn bộ các đoạn Thân bài phải phục vụ như những cột trụ để chống đỡ cho góc nhìn đó, không được tự mâu thuẫn.'),
('415ffae0-fc33-4076-a79e-a0bbb4a05e8a', 'Thế nào là cách tiếp cận ''Balanced approach'' (Partly agree) trong bài Opinion?', 'multiple_choice', '["Đồng ý ở Mở bài nhưng phản đối ở Kết bài.","Công nhận tính hợp lý của quan điểm đề bài trong một số trường hợp (Body 1), nhưng đồng thời chỉ ra những hạn chế hoặc điều kiện ngoại lệ của nó (Body 2).","Nửa câu đầu đồng ý, nửa câu sau phản đối.","Không chọn bên nào cả."]', 'Công nhận tính hợp lý của quan điểm đề bài trong một số trường hợp (Body 1), nhưng đồng thời chỉ ra những hạn chế hoặc điều kiện ngoại lệ của nó (Body 2).', 'Ví dụ: ''Tôi đồng ý rằng công nghệ giúp việc học tiện lợi hơn, nhưng phản đối việc nó có thể thay thế hoàn toàn giáo viên trên lớp''. Đây là cách viết rất sâu sắc.'),
('82c4022f-a01d-45be-b42d-2d3bdc03e91a', 'Dạng bài ''Discuss both views and give your opinion'' yêu cầu sự phân bổ dung lượng bài viết như thế nào?', 'multiple_choice', '["Dành 90% bài viết để nói về quan điểm bạn ủng hộ.","Bắt buộc phải dành sự thảo luận tương đương (Balanced coverage) cho cả Góc nhìn 1 (Body 1) và Góc nhìn 2 (Body 2), sau đó lồng ghép ý kiến của bạn vào.","Chỉ thảo luận góc nhìn mà bạn ghét.","Bỏ qua ý kiến cá nhân."]', 'Bắt buộc phải dành sự thảo luận tương đương (Balanced coverage) cho cả Góc nhìn 1 (Body 1) và Góc nhìn 2 (Body 2), sau đó lồng ghép ý kiến của bạn vào.', 'Lỗi phổ biến nhất là thí sinh chỉ giải thích sơ sài quan điểm họ không thích. Bạn phải hóa vai thành người ủng hộ phe kia để giải thích ''Tại sao họ lại nghĩ vậy'' một cách công bằng.'),
('82c4022f-a01d-45be-b42d-2d3bdc03e91a', 'Khi phân tích Góc nhìn (View) mà bạn KHÔNG ĐỒNG TÌNH, bạn nên dùng ngôn ngữ nào để giữ tính khách quan?', 'multiple_choice', '["I strongly believe that...","It is completely stupid to think that...","Proponents of this view argue that... / It is understandable why some people believe...","I hate this idea..."]', 'Proponents of this view argue that... / It is understandable why some people believe...', 'Sử dụng ''Ngôn ngữ của bên thứ ba'' (Third-party language) giúp bạn tường thuật lại ý kiến của người khác một cách khách quan mà không biến nó thành ý kiến của chính mình.'),
('82c4022f-a01d-45be-b42d-2d3bdc03e91a', 'Trong dạng Discussion Essay, bạn có thể đưa ''Your opinion'' (Ý kiến cá nhân) vào những vị trí nào?', 'multiple_choice', '["Chỉ được để ở Kết bài.","Chỉ để ở Thân bài.","Tốt nhất nên nêu rõ ở Mở bài (Thesis), củng cố nó ở đoạn Body tương ứng với view bạn chọn, và khẳng định lại ở Kết bài.","Giấu nhẹm đi."]', 'Tốt nhất nên nêu rõ ở Mở bài (Thesis), củng cố nó ở đoạn Body tương ứng với view bạn chọn, và khẳng định lại ở Kết bài.', 'Luôn luôn trả lời câu hỏi của đề bài ở ngay đoạn Introduction để đáp ứng tiêu chí ''A clear position throughout''.'),
('39073fd0-4304-4a66-b1be-a24605513e5b', 'Đối với câu hỏi ''Do the advantages OUTWEIGH the disadvantages?'', mục tiêu lập luận của bài là gì?', 'multiple_choice', '["Chỉ liệt kê điểm tốt và điểm xấu rồi dừng lại.","Phải phân tích cả hai mặt, sau đó chứng minh một cách logic rằng sức nặng (tầm quan trọng/hệ quả) của mặt này lớn hơn và áp đảo hoàn toàn mặt kia.","Đếm xem bên nào có số lượng luận điểm nhiều hơn thì bên đó thắng.","Không cần phân tích điểm xấu."]', 'Phải phân tích cả hai mặt, sau đó chứng minh một cách logic rằng sức nặng (tầm quan trọng/hệ quả) của mặt này lớn hơn và áp đảo hoàn toàn mặt kia.', 'Outweigh không phải là số lượng (Quality > Quantity). Bạn có thể có 3 nhược điểm nhỏ, nhưng 1 ưu điểm mang tính cách mạng thì ưu điểm vẫn Outweigh.'),
('39073fd0-4304-4a66-b1be-a24605513e5b', 'Cấu trúc tối ưu cho Thân bài dạng ''Outweigh'' là gì nếu bạn cho rằng Ưu điểm lớn hơn?', 'multiple_choice', '["Body 1: Phân tích Nhược điểm (để nhượng bộ). Body 2: Phân tích Ưu điểm và giải thích tại sao Ưu điểm lại mang tính quyết định, vượt trội hơn.","Cả hai Body đều viết về Ưu điểm.","Trộn lẫn ưu nhược điểm vào cùng một đoạn.","Viết Ưu điểm trước, không viết Nhược điểm."]', 'Body 1: Phân tích Nhược điểm (để nhượng bộ). Body 2: Phân tích Ưu điểm và giải thích tại sao Ưu điểm lại mang tính quyết định, vượt trội hơn.', 'Theo quy tắc ''Save the best for last'', đoạn văn bảo vệ lập trường của bạn nên nằm sau cùng để tạo đòn quyết định (climax) trước khi vào Kết bài.'),
('39073fd0-4304-4a66-b1be-a24605513e5b', 'Từ nối nào hiệu quả nhất để bắt đầu đoạn Body 2 chuyển từ Nhược điểm sang Ưu điểm vượt trội?', 'multiple_choice', '["Similarly,...","In conclusion,...","Despite the aforementioned drawbacks, I am convinced that the benefits are far more significant.","For example,..."]', 'Despite the aforementioned drawbacks, I am convinced that the benefits are far more significant.', 'Câu Topic sentence này thực hiện 2 nhiệm vụ: (1) Tóm lược đoạn 1 bằng một mệnh đề nhượng bộ (Despite...), và (2) Khẳng định dứt khoát chủ đề của đoạn 2.');